import React, { useState } from 'react';
import './App.css';
import KLineChart from './components/KLineChart';
import UASTLChart from './components/UASTLChart';

function App() {
    const [range, setRange] = useState([0, 100]);
    return (
        <div className="main-layout" style={{ background: 'linear-gradient(120deg,#f8fafc,#e0e7ef)' }}>
            <div className="left-panel" style={{ background: 'none', boxShadow: 'none', border: 'none' }}>
                <KLineChart onRangeChange={setRange} />
            </div>
            <div className="right-panel" style={{ background: 'none', boxShadow: 'none', border: 'none' }}>
                <UASTLChart range={range} />
            </div>
        </div>
    );
}

export default App;
